package com.recettealarm.app;import android.app.*;import android.content.*;import android.os.*;import android.media.RingtoneManager;import android.net.Uri;
public class AlarmReceiver extends BroadcastReceiver{public void onReceive(Context c,Intent i){Intent a=new Intent(c,AlarmActivity.class);a.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP);a.putExtras(i);c.startActivity(a); NotificationManager nm=(NotificationManager)c.getSystemService(Context.NOTIFICATION_SERVICE);String ch="alarm"; if(Build.VERSION.SDK_INT>=26){NotificationChannel nc=new NotificationChannel(ch,"Alarmes cuisson",NotificationManager.IMPORTANCE_HIGH);nc.enableVibration(true);nm.createNotificationChannel(nc);} Notification.Builder b=Build.VERSION.SDK_INT>=26?new Notification.Builder(c,ch):new Notification.Builder(c); b.setContentTitle("Temps écoulé !").setContentText(i.getStringExtra("note")).setSmallIcon(android.R.drawable.ic_lock_idle_alarm).setPriority(Notification.PRIORITY_MAX).setAutoCancel(false); nm.notify(99,b.build());}}
